import{_ as a,o as e,c as s,ag as i}from"./chunks/framework.6MCaaFDc.js";const g=JSON.parse('{"title":"Data Integrity","description":"","frontmatter":{},"headers":[],"relativePath":"theory/databases/data-integrity.md","filePath":"theory/databases/data-integrity.md"}'),n={name:"theory/databases/data-integrity.md"};function r(d,t,o,l,h,p){return e(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="data-integrity" tabindex="-1">Data Integrity <a class="header-anchor" href="#data-integrity" aria-label="Permalink to &quot;Data Integrity&quot;">​</a></h1><p>Storing data is only useful if the data is trustworthy. Data integrity is about ensuring that data remains accurate, consistent, and valid throughout its entire lifecycle — from the moment it&#39;s entered to when it&#39;s retrieved years later.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11–12</p><p>Data integrity and validation are introduced in Grade 11. SQL injection as a threat is a Grade 12 extension.</p></div><hr><h2 id="what-is-data-integrity" tabindex="-1">What is Data Integrity? <a class="header-anchor" href="#what-is-data-integrity" aria-label="Permalink to &quot;What is Data Integrity?&quot;">​</a></h2><p><strong>Data integrity</strong> means the data in a database is:</p><ul><li><strong>Accurate</strong> — reflects reality</li><li><strong>Consistent</strong> — the same value in all related tables</li><li><strong>Valid</strong> — meets defined rules and constraints</li><li><strong>Reliable</strong> — can be trusted for decision-making</li></ul><hr><h2 id="types-of-data-integrity" tabindex="-1">Types of Data Integrity <a class="header-anchor" href="#types-of-data-integrity" aria-label="Permalink to &quot;Types of Data Integrity&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>What it ensures</th><th>How enforced</th></tr></thead><tbody><tr><td><strong>Entity integrity</strong></td><td>Primary key is unique and not NULL</td><td>PK constraint</td></tr><tr><td><strong>Referential integrity</strong></td><td>Foreign key matches an existing PK</td><td>FK constraint</td></tr><tr><td><strong>Domain integrity</strong></td><td>Values match the field&#39;s data type and rules</td><td>Data type, validation rules</td></tr><tr><td><strong>User-defined integrity</strong></td><td>Custom business rules</td><td>CHECK constraints, triggers</td></tr></tbody></table><h3 id="entity-integrity" tabindex="-1">Entity Integrity <a class="header-anchor" href="#entity-integrity" aria-label="Permalink to &quot;Entity Integrity&quot;">​</a></h3><p>Every table must have a primary key.<br> The PK must be unique and cannot be NULL.</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Students</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  StudentID </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INTEGER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> PRIMARY KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- enforces entity integrity</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  FirstName </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TEXT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> NOT NULL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="referential-integrity" tabindex="-1">Referential Integrity <a class="header-anchor" href="#referential-integrity" aria-label="Permalink to &quot;Referential Integrity&quot;">​</a></h3><p>A foreign key must reference an existing primary key.<br> You cannot add a mark for a student who doesn&#39;t exist.</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Cannot insert a Mark with a StudentID that doesn&#39;t exist in Student</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INSERT INTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Marks (StudentID, Mark) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">VALUES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9999</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">85</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- ERROR if StudentID 9999 not in Student</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>Cascade actions:</strong></p><table tabindex="0"><thead><tr><th>Action</th><th>Effect</th></tr></thead><tbody><tr><td>CASCADE DELETE</td><td>Deleting a parent record also deletes related child records</td></tr><tr><td>RESTRICT</td><td>Prevents deletion of parent if child records exist</td></tr><tr><td>SET NULL</td><td>Sets FK to NULL when parent is deleted</td></tr></tbody></table><hr><h2 id="data-validation" tabindex="-1">Data Validation <a class="header-anchor" href="#data-validation" aria-label="Permalink to &quot;Data Validation&quot;">​</a></h2><p><strong>Validation</strong> is the process of checking that data meets predefined rules before it is accepted.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Validation vs Verification</p><p><strong>Validation</strong> — computer checks data meets rules (is the mark between 0 and 100?)<br><strong>Verification</strong> — human or system confirms data was entered correctly (re-enter your password)</p></div><h3 id="validation-types" tabindex="-1">Validation Types <a class="header-anchor" href="#validation-types" aria-label="Permalink to &quot;Validation Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Rule</th><th>Example</th><th>Error message</th></tr></thead><tbody><tr><td><strong>Presence check</strong></td><td>Field cannot be empty</td><td>Name must not be blank</td><td>&quot;Name is required&quot;</td></tr><tr><td><strong>Type check</strong></td><td>Must match expected data type</td><td>Mark must be a number</td><td>&quot;Enter a numeric value&quot;</td></tr><tr><td><strong>Range check</strong></td><td>Must be within min–max</td><td>Mark: 0–100</td><td>&quot;Mark must be between 0 and 100&quot;</td></tr><tr><td><strong>Length check</strong></td><td>Must meet min/max character count</td><td>ID: exactly 13 digits</td><td>&quot;ID number must be 13 digits&quot;</td></tr><tr><td><strong>Format check</strong></td><td>Must match a pattern</td><td>Email must contain @ and .</td><td>&quot;Invalid email format&quot;</td></tr><tr><td><strong>Lookup check</strong></td><td>Must match a value in a list</td><td>Province must be one of 9 SA provinces</td><td>&quot;Select a valid province&quot;</td></tr><tr><td><strong>Check digit</strong></td><td>Calculated digit validates the number</td><td>Barcode, SA ID last digit</td><td>&quot;Invalid ID number&quot;</td></tr><tr><td><strong>Cross-field check</strong></td><td>Relationship between two fields</td><td>End date must be after start date</td><td>&quot;End date must be after start date&quot;</td></tr></tbody></table><hr><h2 id="validation-in-microsoft-access" tabindex="-1">Validation in Microsoft Access <a class="header-anchor" href="#validation-in-microsoft-access" aria-label="Permalink to &quot;Validation in Microsoft Access&quot;">​</a></h2><p><strong>Input mask</strong> — controls the format of data entry:</p><ul><li><code>000-000-0000</code> — phone number format</li><li><code>&gt;L&lt;??????????</code> — capitalised first letter</li></ul><p><strong>Validation rule</strong> — expression that data must satisfy:</p><ul><li><code>&gt;= 0 And &lt;= 100</code> — for a mark field</li><li><code>&gt;= Date()</code> — for a future date</li><li><code>In (&quot;Gauteng&quot;, &quot;Western Cape&quot;, &quot;KwaZulu-Natal&quot;)</code> — for a province</li></ul><p><strong>Validation text</strong> — error message shown when rule is violated:</p><ul><li>&quot;Mark must be between 0 and 100&quot;</li></ul><p><strong>Required</strong> — setting Yes means field cannot be left blank</p><hr><h2 id="data-security" tabindex="-1">Data Security <a class="header-anchor" href="#data-security" aria-label="Permalink to &quot;Data Security&quot;">​</a></h2><p><strong>Data security</strong> protects data from unauthorised access, corruption, or loss.</p><h3 id="user-accounts-and-permissions" tabindex="-1">User Accounts and Permissions <a class="header-anchor" href="#user-accounts-and-permissions" aria-label="Permalink to &quot;User Accounts and Permissions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Access Level</th><th>Rights</th></tr></thead><tbody><tr><td><strong>Administrator / DBA</strong></td><td>Full access — read, write, delete, change structure</td></tr><tr><td><strong>Editor</strong></td><td>Read and write — can add and update data</td></tr><tr><td><strong>Viewer / Read-only</strong></td><td>Read only — cannot modify data</td></tr><tr><td><strong>No access</strong></td><td>Cannot view or modify data</td></tr></tbody></table><p><strong>Principle of least privilege:</strong> users are given only the minimum access needed for their role.</p><h3 id="password-policies" tabindex="-1">Password Policies <a class="header-anchor" href="#password-policies" aria-label="Permalink to &quot;Password Policies&quot;">​</a></h3><ul><li>Minimum length (8+ characters)</li><li>Complexity (uppercase, lowercase, numbers, symbols)</li><li>Expiry (force periodic password changes)</li><li>No reuse of recent passwords</li><li>Account lockout after failed attempts</li></ul><h3 id="audit-trail" tabindex="-1">Audit Trail <a class="header-anchor" href="#audit-trail" aria-label="Permalink to &quot;Audit Trail&quot;">​</a></h3><p>An <strong>audit trail</strong> (audit log) records:</p><ul><li>Who accessed data</li><li>When they accessed it</li><li>What changes were made</li><li>From which device/location</li></ul><p>This allows detection of suspicious activity and reconstruction of events after a breach.</p><hr><h2 id="backup-and-recovery" tabindex="-1">Backup and Recovery <a class="header-anchor" href="#backup-and-recovery" aria-label="Permalink to &quot;Backup and Recovery&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strategy</th><th>Description</th></tr></thead><tbody><tr><td><strong>Full backup</strong></td><td>Complete copy of all data</td></tr><tr><td><strong>Incremental backup</strong></td><td>Only changes since last backup</td></tr><tr><td><strong>Differential backup</strong></td><td>Changes since last full backup</td></tr><tr><td><strong>Transaction log backup</strong></td><td>Record of every database transaction</td></tr></tbody></table><p><strong>Recovery point objective (RPO):</strong> maximum acceptable data loss (how old can the backup be?)<br><strong>Recovery time objective (RTO):</strong> maximum acceptable downtime before systems must be restored</p><hr><h2 id="sql-injection" tabindex="-1">SQL Injection <a class="header-anchor" href="#sql-injection" aria-label="Permalink to &quot;SQL Injection&quot;">​</a></h2><p><strong>SQL injection</strong> is a cyberattack where malicious SQL code is inserted into a form input field, which is then executed by the database.</p><h3 id="how-it-works" tabindex="-1">How it works: <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works:&quot;">​</a></h3><p><strong>Normal login query:</strong></p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Username </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ayden&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> Password</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;mypassword&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Attacker enters in the username field:</strong> <code>ayden&#39; OR &#39;1&#39;=&#39;1</code></p><p><strong>Resulting query:</strong></p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Username </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ayden&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> OR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;1&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> Password</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Since <code>&#39;1&#39;=&#39;1&#39;</code> is always true, this returns all users — bypassing authentication entirely.</p><h3 id="what-attackers-can-do" tabindex="-1">What attackers can do: <a class="header-anchor" href="#what-attackers-can-do" aria-label="Permalink to &quot;What attackers can do:&quot;">​</a></h3><ul><li>Bypass login authentication</li><li>Read all data from the database</li><li>Delete or corrupt data</li><li>Execute admin operations</li></ul><h3 id="prevention" tabindex="-1">Prevention: <a class="header-anchor" href="#prevention" aria-label="Permalink to &quot;Prevention:&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Measure</th><th>How it helps</th></tr></thead><tbody><tr><td><strong>Parameterised queries</strong></td><td>Input treated as data, never as SQL code — most effective</td></tr><tr><td><strong>Input validation</strong></td><td>Reject unexpected characters (quotes, semicolons)</td></tr><tr><td><strong>Escaping special characters</strong></td><td>Neutralise dangerous characters before processing</td></tr><tr><td><strong>Least privilege</strong></td><td>Database account only has minimum necessary permissions</td></tr><tr><td><strong>Web Application Firewall (WAF)</strong></td><td>Detects and blocks malicious requests</td></tr><tr><td><strong>Error handling</strong></td><td>Don&#39;t display database error messages to users</td></tr></tbody></table><p><strong>Parameterised query example (PHP):</strong></p><div class="language-php vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Safe — parameter not interpreted as SQL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$stmt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $pdo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">prepare</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Username </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ? </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> Password</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ?&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$stmt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">execute</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([$username, $password]);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Data integrity</strong></td><td>Accuracy, consistency, and validity of data</td></tr><tr><td><strong>Entity integrity</strong></td><td>PK must be unique and not NULL</td></tr><tr><td><strong>Referential integrity</strong></td><td>FK must reference an existing PK</td></tr><tr><td><strong>Domain integrity</strong></td><td>Values must match data type and defined rules</td></tr><tr><td><strong>Validation</strong></td><td>Computer checks data meets rules before accepting</td></tr><tr><td><strong>Verification</strong></td><td>Confirming data was entered correctly</td></tr><tr><td><strong>Audit trail</strong></td><td>Log of who accessed/changed data and when</td></tr><tr><td><strong>SQL injection</strong></td><td>Attack inserting malicious SQL into a form input</td></tr><tr><td><strong>Parameterised query</strong></td><td>Query using placeholders — prevents SQL injection</td></tr><tr><td><strong>Least privilege</strong></td><td>Users given only minimum necessary access rights</td></tr><tr><td><strong>Check digit</strong></td><td>Calculated digit used to validate a number (e.g. barcode)</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the difference between validation and verification?&quot;</strong> — Validation: computer checks data meets rules (range, type, format); Verification: confirming data was entered correctly (double entry, proofreading)</p></li><li><p><strong>&quot;Give FOUR types of validation with examples&quot;</strong> — Presence check (name required); Range check (mark 0–100); Type check (mark must be integer); Format check (email must contain @); Length check (ID = 13 digits)</p></li><li><p><strong>&quot;What is referential integrity?&quot;</strong> — Rule that a foreign key must reference an existing primary key in the related table — prevents orphan records</p></li><li><p><strong>&quot;Explain SQL injection. How can it be prevented?&quot;</strong> — Attacker inserts malicious SQL into a form field; it executes against the database; prevent with parameterised queries, input validation, least privilege</p></li><li><p><strong>&quot;What is an audit trail? Why is it important?&quot;</strong> — A log recording who accessed data, what changes were made, and when; important for detecting unauthorised access and investigating security incidents</p></li></ol></div>`,71)])])}const u=a(n,[["render",r]]);export{g as __pageData,u as default};
